from pathlib import Path
for fname, chunks in [('model.py', [(1,70),(71,140),(141,210),(211,260)]), ('predict.py', [(1,75)])]:
    p=Path(fname)
    print(f'===== {fname} exists={p.exists()} size={p.stat().st_size if p.exists() else None} =====')
    if not p.exists():
        continue
    lines=p.read_text(errors='replace').splitlines()
    for a,b in chunks:
        if a>len(lines):
            continue
        print(f'--- {fname} lines {a}-{min(b,len(lines))} ---')
        for i in range(a-1, min(b,len(lines))):
            s=lines[i]
            if len(s)>140:
                s=s[:140]+'...'
            print(f'{i+1:04d}: {s}')
